#include <stdio.h>
#include <stdint.h>
const long long MOD = 998244353LL;
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            sum += x;
        }
        long long s = sum % MOD;
        long long ans = s * ((s - 1 + MOD) % MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

